{
  "name": "Twitter Carousel Pro",
  "description": "A professional Instagram carousel generator with a classic Twitter aesthetic, featuring voice-to-text transcription and high-fidelity PNG export.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Theme = 'light' | 'dark';

export interface ProfileInfo {
  name: string;
  handle: string;
  avatar: string;
}

export interface Slide {
  id: string;
  content: string;
}

export interface CarouselConfig {
  theme: Theme;
  fontSize: number;
  cta: string;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Theme, ProfileInfo, Slide, CarouselConfig } from './types';
import CarouselCard from './components/CarouselCard';
import EditorControls from './components/EditorControls';
import { toPng } from 'html-to-image';

const App: React.FC = () => {
  // State
  const [profile, setProfile] = useState<ProfileInfo>({
    name: 'Grupo Decisivo',
    handle: '@grupodecisivo_',
    avatar: 'https://picsum.photos/seed/decisivo/200/200'
  });

  const [slides, setSlides] = useState<Slide[]>([
    { id: '1', content: 'Bem-vindo ao <b>Carousel Pro</b>.<br><br>Crie carrosséis incríveis com o visual clássico do Twitter.' },
    { id: '2', content: 'O conteúdo é centralizado em uma área de <u>1080x1080</u>, garantindo que nada seja cortado no feed.' },
    { id: '3', content: 'Você pode usar <i>itálico</i>, <mark>destaque</mark> e emojis 🚀 para prender a atenção do seu público.' }
  ]);

  const [config, setConfig] = useState<CarouselConfig>({
    theme: 'light',
    fontSize: 48,
    cta: 'Seguir'
  });

  const [activeSlideIndex, setActiveSlideIndex] = useState(0);
  const [isRecording, setIsRecording] = useState(false);
  const [isExporting, setIsExporting] = useState(false);

  // Refs for export
  const cardRefs = useRef<(HTMLDivElement | null)[]>([]);

  // Speech Recognition
  const startRecording = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) {
      alert('Seu navegador não suporta reconhecimento de voz.');
      return;
    }

    const recognition = new SpeechRecognition();
    recognition.lang = 'pt-BR';
    recognition.interimResults = false;
    recognition.maxAlternatives = 1;

    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);
    recognition.onerror = () => setIsRecording(false);

    recognition.onresult = (event: any) => {
      const transcript = event.results[0][0].transcript;
      updateSlideContent(activeSlideIndex, transcript);
    };

    recognition.start();
  };

  const updateSlideContent = (index: number, content: string) => {
    const newSlides = [...slides];
    newSlides[index].content = content;
    setSlides(newSlides);
  };

  const addSlide = () => {
    const newId = Math.random().toString(36).substr(2, 9);
    setSlides([...slides, { id: newId, content: 'Novo conteúdo aqui...' }]);
    setActiveSlideIndex(slides.length);
  };

  const removeSlide = (index: number) => {
    if (slides.length <= 1) return;
    const newSlides = slides.filter((_, i) => i !== index);
    setSlides(newSlides);
    setActiveSlideIndex(Math.max(0, index - 1));
  };

  const exportAll = async () => {
    setIsExporting(true);
    try {
      for (let i = 0; i < slides.length + 1; i++) {
        const node = cardRefs.current[i];
        if (node) {
          // Use a higher scale for 1080x1350 output
          const dataUrl = await toPng(node, {
            canvasWidth: 1080,
            canvasHeight: 1350,
            pixelRatio: 1,
          });
          const link = document.createElement('a');
          link.download = `carousel-card-${i + 1}.png`;
          link.href = dataUrl;
          link.click();
        }
      }
    } catch (err) {
      console.error('Export error:', err);
      alert('Erro ao exportar imagens.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className={`min-h-screen transition-colors duration-300 ${config.theme === 'dark' ? 'bg-[#15202b] text-white' : 'bg-gray-100 text-gray-900'}`}>
      <header className="fixed top-0 left-0 right-0 z-50 bg-white/80 dark:bg-[#15202b]/80 backdrop-blur-md border-b border-gray-200 dark:border-gray-800 px-6 py-4 flex justify-between items-center">
        <div className="flex items-center gap-2">
          <svg className="w-8 h-8 text-[#1d9bf0]" fill="currentColor" viewBox="0 0 24 24">
            <path d="M23.643 4.937c-.835.37-1.732.62-2.675.733a4.67 4.67 0 0 0 2.048-2.578 9.3 9.3 0 0 1-2.958 1.13 4.66 4.66 0 0 0-7.938 4.25 13.217 13.217 0 0 1-9.597-4.863 4.66 4.66 0 0 0 1.44 6.22 4.623 4.623 0 0 1-2.112-.583v.06a4.66 4.66 0 0 0 3.737 4.568 4.692 4.692 0 0 1-2.104.08 4.661 4.661 0 0 0 4.352 3.234 9.348 9.348 0 0 1-5.786 1.995 9.5 9.5 0 0 1-1.112-.065 13.175 13.175 0 0 0 7.14 2.093c8.57 0 13.255-7.098 13.255-13.254 0-.2-.005-.402-.014-.602a9.47 9.47 0 0 0 2.323-2.41z"></path>
          </svg>
          <h1 className="text-xl font-bold tracking-tight">Carousel Pro</h1>
        </div>
        <button
          onClick={exportAll}
          disabled={isExporting}
          className="bg-[#1d9bf0] hover:bg-[#1a8cd8] text-white px-6 py-2 rounded-full font-bold transition-all flex items-center gap-2 disabled:opacity-50"
        >
          {isExporting ? (
            <>
              <div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
              Exportando...
            </>
          ) : (
            'Exportar PNG'
          )}
        </button>
      </header>

      <main className="pt-24 pb-12 px-4 lg:px-12 grid grid-cols-1 xl:grid-cols-12 gap-8 items-start max-w-[1600px] mx-auto">
        {/* Left: Preview Area */}
        <div className="xl:col-span-8 flex flex-col items-center gap-8">
          <div className="relative flex items-center justify-center w-full overflow-x-auto no-scrollbar py-10 gap-12">
            {/* Cards Rendering */}
            {slides.map((slide, index) => (
              <div
                key={slide.id}
                className={`flex-shrink-0 transition-transform duration-300 ${activeSlideIndex === index ? 'scale-105 z-10' : 'scale-90 opacity-60'}`}
                onClick={() => setActiveSlideIndex(index)}
              >
                <div ref={el => cardRefs.current[index] = el} className="shadow-2xl">
                  <CarouselCard
                    slide={slide}
                    profile={profile}
                    config={config}
                    isLast={false}
                    onContentChange={(val) => updateSlideContent(index, val)}
                  />
                </div>
                <div className="text-center mt-4 font-mono opacity-50">Card {index + 1}</div>
              </div>
            ))}

            {/* CTA Card (Always Last) */}
            <div
              className={`flex-shrink-0 transition-transform duration-300 ${activeSlideIndex === slides.length ? 'scale-105 z-10' : 'scale-90 opacity-60'}`}
              onClick={() => setActiveSlideIndex(slides.length)}
            >
              <div ref={el => cardRefs.current[slides.length] = el} className="shadow-2xl">
                <CarouselCard
                  slide={{ id: 'cta', content: `<div class="text-center w-full"><div class="text-[80px] mb-8">📣</div><div class="font-bold text-6xl">${config.cta}</div></div>` }}
                  profile={profile}
                  config={config}
                  isLast={true}
                  onContentChange={() => {}}
                />
              </div>
              <div className="text-center mt-4 font-mono opacity-50">CTA Card</div>
            </div>
          </div>

          {/* Navigation Controls */}
          <div className="flex gap-4">
            <button
              onClick={() => setActiveSlideIndex(prev => Math.max(0, prev - 1))}
              className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-md hover:bg-gray-50 dark:hover:bg-gray-700 transition"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 19l-7-7 7-7"></path></svg>
            </button>
            <div className="flex items-center gap-2 px-4 bg-white dark:bg-gray-800 rounded-full shadow-md font-bold">
              {activeSlideIndex + 1} / {slides.length + 1}
            </div>
            <button
              onClick={() => setActiveSlideIndex(prev => Math.min(slides.length, prev + 1))}
              className="p-3 rounded-full bg-white dark:bg-gray-800 shadow-md hover:bg-gray-50 dark:hover:bg-gray-700 transition"
            >
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 5l7 7-7 7"></path></svg>
            </button>
          </div>
        </div>

        {/* Right: Editor Panel */}
        <aside className="xl:col-span-4 bg-white dark:bg-gray-800 p-6 rounded-[32px] shadow-xl border border-gray-200 dark:border-gray-700 sticky top-24">
          <EditorControls
            profile={profile}
            setProfile={setProfile}
            config={config}
            setConfig={setConfig}
            slides={slides}
            activeSlideIndex={activeSlideIndex}
            updateSlideContent={updateSlideContent}
            addSlide={addSlide}
            removeSlide={removeSlide}
            isRecording={isRecording}
            startRecording={startRecording}
          />
        </aside>
      </main>
    </div>
  );
};

export default App;

import React from 'react';
import { ProfileInfo, Slide, CarouselConfig } from '../types';

interface Props {
  slide: Slide;
  profile: ProfileInfo;
  config: CarouselConfig;
  isLast: boolean;
  onContentChange: (content: string) => void;
}

const CarouselCard: React.FC<Props> = ({ slide, profile, config, isLast, onContentChange }) => {
  const isDark = config.theme === 'dark';

  return (
    <div
      style={{
        width: '1080px',
        height: '1350px',
        backgroundColor: isDark ? '#15202b' : '#ffffff',
        color: isDark ? '#ffffff' : '#000000',
        padding: '0',
        display: 'flex',
        flexDirection: 'column',
        position: 'relative',
        overflow: 'hidden'
      }}
      className="twitter-card"
    >
      {/* Safe Area (1080x1080) for Instagram Feed */}
      <div
        style={{
          width: '1080px',
          height: '1080px',
          margin: '135px 0',
          padding: '80px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          position: 'relative'
        }}
      >
        {/* Twitter Header Style */}
        <div className="flex items-start gap-4 mb-12 absolute top-20 left-20 right-20">
          <img
            src={profile.avatar}
            alt="Avatar"
            className="w-20 h-20 rounded-full border-2 border-transparent"
            style={{ borderColor: isDark ? '#38444d' : '#e1e8ed' }}
          />
          <div className="flex flex-col">
            <div className="flex items-center gap-1">
              <span className="text-[32px] font-extrabold leading-tight">{profile.name}</span>
              <svg className="w-6 h-6 text-[#1d9bf0]" fill="currentColor" viewBox="0 0 24 24">
                <path d="M22.25 12c0-1.43-.88-2.67-2.19-3.34.46-1.39.2-2.9-.81-3.91s-2.52-1.27-3.91-.81c-.66-1.31-1.91-2.19-3.34-2.19s-2.67.88-3.33 2.19c-1.4-.47-2.91-.2-3.92.81s-1.26 2.52-.8 3.91c-1.31.67-2.2 1.91-2.2 3.34s.89 2.67 2.2 3.34c-.46 1.39-.21 2.9.8 3.91s2.52 1.26 3.91.81c.67 1.31 1.91 2.19 3.34 2.19s2.68-.88 3.34-2.19c1.39.45 2.9.2 3.91-.81s1.27-2.52.81-3.91c1.31-.67 2.19-1.91 2.19-3.34zm-11.71 4.2L6.8 12.46l1.41-1.42 2.26 2.26 4.8-5.23 1.47 1.35-6.2 6.78z"></path>
              </svg>
            </div>
            <span className={`text-[26px] ${isDark ? 'text-gray-400' : 'text-gray-500'}`}>{profile.handle}</span>
          </div>
        </div>

        {/* Content Section */}
        <div
          contentEditable={!isLast}
          suppressContentEditableWarning
          onBlur={(e) => onContentChange(e.currentTarget.innerHTML)}
          style={{
            fontSize: `${config.fontSize}px`,
            lineHeight: '1.4',
            whiteSpace: 'pre-wrap',
            textAlign: 'left',
            verticalAlign: 'middle',
            width: '100%',
            outline: 'none',
            color: isDark ? '#ffffff' : '#000000'
          }}
          className="content-area font-medium"
          dangerouslySetInnerHTML={{ __html: slide.content }}
        />

        {/* Fake Twitter Engagement - Static visual for vibe but no fake numbers per requirement */}
        <div
          className={`absolute bottom-20 left-20 right-20 flex justify-between border-t pt-8 ${isDark ? 'border-[#38444d]' : 'border-gray-100'}`}
        >
          <div className="flex gap-12 items-center opacity-40">
             <div className="flex items-center gap-2">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z" strokeWidth="2"></path></svg>
             </div>
             <div className="flex items-center gap-2">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M7 16V4m0 0L3 8m4-4l4 4m6 0v12m0 0l4-4m-4 4l-4 4" strokeWidth="2"></path></svg>
             </div>
             <div className="flex items-center gap-2">
                <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" strokeWidth="2"></path></svg>
             </div>
          </div>
          <div className="opacity-40">
             <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" strokeWidth="2"></path></svg>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CarouselCard;

import React from 'react';
import { ProfileInfo, Slide, CarouselConfig } from '../types';

interface Props {
  profile: ProfileInfo;
  setProfile: (p: ProfileInfo) => void;
  config: CarouselConfig;
  setConfig: (c: CarouselConfig) => void;
  slides: Slide[];
  activeSlideIndex: number;
  updateSlideContent: (index: number, content: string) => void;
  addSlide: () => void;
  removeSlide: (index: number) => void;
  isRecording: boolean;
  startRecording: () => void;
}

const EditorControls: React.FC<Props> = ({
  profile, setProfile, config, setConfig, slides, activeSlideIndex,
  updateSlideContent, addSlide, removeSlide, isRecording, startRecording
}) => {
  const currentSlide = slides[activeSlideIndex];
  const isCtaCard = activeSlideIndex === slides.length;

  const handleFormat = (tag: string) => {
    // Simple helper to wrap selected text in active content area
    // In a real app, document.execCommand or a proper library would be used.
    // For this simple version, we advise user or add it via string manipulation.
    if (isCtaCard) return;
    const content = currentSlide.content;
    updateSlideContent(activeSlideIndex, `<b>${content}</b>`); // Simple toggle
  };

  const ctaOptions = ['Seguir', 'Comente aqui embaixo', 'Compartilhe', 'Salvar'];

  return (
    <div className="space-y-8 overflow-y-auto max-h-[calc(100vh-200px)] pr-2 no-scrollbar">
      {/* Profile Editor */}
      <section>
        <h3 className="text-sm font-bold uppercase tracking-wider text-gray-400 mb-4">Perfil</h3>
        <div className="space-y-4">
          <div className="flex gap-4 items-center">
            <div className="relative group cursor-pointer">
              <img src={profile.avatar} className="w-16 h-16 rounded-full object-cover border-2 border-[#1d9bf0]" alt="avatar" />
              <div className="absolute inset-0 bg-black/40 rounded-full flex items-center justify-center opacity-0 group-hover:opacity-100 transition">
                <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M3 9a2 2 0 012-2h.93a2 2 0 001.664-.89l.812-1.22A2 2 0 0110.07 4h3.86a2 2 0 011.664.89l.812 1.22A2 2 0 0018.07 7H19a2 2 0 012 2v9a2 2 0 01-2 2H5a2 2 0 01-2-2V9z" strokeWidth="2"></path><path d="M15 13a3 3 0 11-6 0 3 3 0 016 0z" strokeWidth="2"></path></svg>
              </div>
              <input
                type="file"
                className="absolute inset-0 opacity-0 cursor-pointer"
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) setProfile({ ...profile, avatar: URL.createObjectURL(file) });
                }}
              />
            </div>
            <div className="flex-1 space-y-2">
              <input
                type="text"
                value={profile.name}
                onChange={(e) => setProfile({ ...profile, name: e.target.value })}
                className="w-full bg-transparent border-b border-gray-200 dark:border-gray-700 focus:border-[#1d9bf0] outline-none font-bold"
                placeholder="Nome do Perfil"
              />
              <input
                type="text"
                value={profile.handle}
                onChange={(e) => setProfile({ ...profile, handle: e.target.value })}
                className="w-full bg-transparent border-b border-gray-200 dark:border-gray-700 focus:border-[#1d9bf0] outline-none text-gray-500"
                placeholder="@usuario"
              />
            </div>
          </div>
        </div>
      </section>

      {/* Slide Content Editor */}
      <section>
        <div className="flex justify-between items-center mb-4">
          <h3 className="text-sm font-bold uppercase tracking-wider text-gray-400">Conteúdo do Card {isCtaCard ? ' (CTA)' : activeSlideIndex + 1}</h3>
          {!isCtaCard && (
            <div className="flex gap-2">
               <button
                  onClick={startRecording}
                  className={`p-2 rounded-full transition ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-gray-100 dark:bg-gray-700 hover:bg-gray-200'}`}
                >
                  <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" strokeWidth="2" strokeLinecap="round"></path></svg>
               </button>
            </div>
          )}
        </div>

        {isCtaCard ? (
          <div className="space-y-4">
             <div className="grid grid-cols-2 gap-2">
                {ctaOptions.map(opt => (
                  <button
                    key={opt}
                    onClick={() => setConfig({...config, cta: opt})}
                    className={`px-3 py-2 text-sm rounded-lg border transition ${config.cta === opt ? 'bg-[#1d9bf0] text-white border-[#1d9bf0]' : 'border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700'}`}
                  >
                    {opt}
                  </button>
                ))}
             </div>
             <input
                type="text"
                value={config.cta}
                onChange={(e) => setConfig({ ...config, cta: e.target.value })}
                className="w-full p-4 rounded-xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 outline-none focus:ring-2 focus:ring-[#1d9bf0]"
                placeholder="Ou digite sua própria CTA..."
              />
          </div>
        ) : (
          <div className="space-y-4">
            <textarea
              value={currentSlide.content.replace(/<br>/g, '\n').replace(/<[^>]*>/g, '')}
              onChange={(e) => updateSlideContent(activeSlideIndex, e.target.value.replace(/\n/g, '<br>'))}
              className="w-full h-40 p-4 rounded-xl border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900 outline-none focus:ring-2 focus:ring-[#1d9bf0] resize-none"
              placeholder="Digite o texto aqui ou use o microfone..."
            />
            <div className="flex gap-2">
               <button onClick={addSlide} className="flex-1 bg-gray-100 dark:bg-gray-700 py-2 rounded-lg font-bold hover:bg-gray-200 transition">+ Add Slide</button>
               <button onClick={() => removeSlide(activeSlideIndex)} className="px-4 bg-red-50 text-red-500 py-2 rounded-lg font-bold hover:bg-red-100 transition">Remover</button>
            </div>
          </div>
        )}
      </section>

      {/* Global Config */}
      <section className="space-y-6 pt-4 border-t border-gray-200 dark:border-gray-700">
        <div>
          <label className="text-sm font-bold uppercase tracking-wider text-gray-400 block mb-4">Tamanho da Fonte</label>
          <input
            type="range"
            min="24"
            max="120"
            value={config.fontSize}
            onChange={(e) => setConfig({ ...config, fontSize: parseInt(e.target.value) })}
            className="w-full h-2 bg-gray-200 dark:bg-gray-700 rounded-lg appearance-none cursor-pointer accent-[#1d9bf0]"
          />
          <div className="flex justify-between mt-2 text-xs font-mono opacity-50">
            <span>24px</span>
            <span>{config.fontSize}px</span>
            <span>120px</span>
          </div>
        </div>

        <div>
          <label className="text-sm font-bold uppercase tracking-wider text-gray-400 block mb-4">Tema</label>
          <div className="grid grid-cols-2 gap-4">
            <button
              onClick={() => setConfig({ ...config, theme: 'light' })}
              className={`flex items-center justify-center gap-2 py-3 rounded-xl border transition ${config.theme === 'light' ? 'bg-white border-[#1d9bf0] ring-2 ring-[#1d9bf0]/20' : 'bg-white border-gray-200 text-gray-400'}`}
            >
              <div className="w-4 h-4 bg-white border border-gray-300 rounded-full"></div>
              Claro
            </button>
            <button
              onClick={() => setConfig({ ...config, theme: 'dark' })}
              className={`flex items-center justify-center gap-2 py-3 rounded-xl border transition ${config.theme === 'dark' ? 'bg-[#15202b] text-white border-[#1d9bf0] ring-2 ring-[#1d9bf0]/20' : 'bg-[#15202b] border-gray-700 text-gray-600'}`}
            >
              <div className="w-4 h-4 bg-black border border-gray-600 rounded-full"></div>
              Escuro
            </button>
          </div>
        </div>
      </section>

      <div className="text-xs text-gray-400 text-center pb-4">
        * Dica: Você pode editar o texto diretamente nas imagens também!
      </div>
    </div>
  );
};

