import React, { useState, useRef, useEffect } from 'react';
import { ProfileInfo, Slide, CarouselConfig } from './types';
import CarouselCard from './components/CarouselCard';
import EditorControls from './components/EditorControls';
import { toPng } from 'html-to-image';

const App: React.FC = () => {
  const [profile, setProfile] = useState<ProfileInfo>({
    name: 'Grupo Decisivo',
    handle: '@grupodecisivo_',
    avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=decisivo'
  });

  const [slides, setSlides] = useState<Slide[]>([
    { id: '1', content: 'Transforme seus pensamentos em carrosséis profissionais no estilo <b>Twitter</b>.' },
    { id: '2', content: 'O conteúdo é automaticamente centralizado na zona de segurança para o <u>Instagram</u>.' },
    { id: '3', content: 'Use o menu lateral para ditar seu texto e gerar todos os cards de uma vez.' }
  ]);

  const [config, setConfig] = useState<CarouselConfig>({
    theme: 'light',
    fontSize: 48,
    cta: 'Seguir'
  });

  const [isExporting, setIsExporting] = useState(false);
  const cardRefs = useRef<(HTMLDivElement | null)[]>([]);

  const handleBulkGenerate = (text: string) => {
    // Split by double newlines or single if long enough? Let's use double for clear separation.
    const parts = text.split(/\n\n+/).filter(p => p.trim().length > 0);
    if (parts.length === 0) return;

    const newSlides = parts.map((content, idx) => ({
      id: Math.random().toString(36).substr(2, 9),
      content: content.trim().replace(/\n/g, '<br>')
    }));
    setSlides(newSlides);
  };

  const exportAll = async () => {
    setIsExporting(true);
    try {
      // Export content slides
      for (let i = 0; i <= slides.length; i++) {
        const node = cardRefs.current[i];
        if (node) {
          const dataUrl = await toPng(node, {
            canvasWidth: 1080,
            canvasHeight: 1350,
            pixelRatio: 2, // Higher quality
          });
          const link = document.createElement('a');
          link.download = `card-${i + 1}.png`;
          link.href = dataUrl;
          link.click();
          // Small delay to prevent browser download blocking
          await new Promise(r => setTimeout(r, 200));
        }
      }
    } catch (err) {
      console.error('Export error:', err);
      alert('Erro ao exportar. Tente novamente.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className={`flex h-screen w-screen transition-colors duration-300 ${config.theme === 'dark' ? 'bg-[#10171e] text-white' : 'bg-slate-50 text-slate-900'}`}>
      {/* Sidebar - Left Menu */}
      <aside className="w-[380px] h-full flex flex-col border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-[#15202b] shadow-2xl z-20 overflow-hidden">
        <div className="p-6 flex items-center gap-3 border-b border-slate-100 dark:border-slate-800">
          <div className="bg-[#1d9bf0] p-2 rounded-xl">
             <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 24 24">
                <path d="M23.643 4.937c-.835.37-1.732.62-2.675.733a4.67 4.67 0 0 0 2.048-2.578 9.3 9.3 0 0 1-2.958 1.13 4.66 4.66 0 0 0-7.938 4.25 13.217 13.217 0 0 1-9.597-4.863 4.66 4.66 0 0 0 1.44 6.22 4.623 4.623 0 0 1-2.112-.583v.06a4.66 4.66 0 0 0 3.737 4.568 4.692 4.692 0 0 1-2.104.08 4.661 4.661 0 0 0 4.352 3.234 9.348 9.348 0 0 1-5.786 1.995 9.5 9.5 0 0 1-1.112-.065 13.175 13.175 0 0 0 7.14 2.093c8.57 0 13.255-7.098 13.255-13.254 0-.2-.005-.402-.014-.602a9.47 9.47 0 0 0 2.323-2.41z"></path>
             </svg>
          </div>
          <h1 className="text-xl font-bold tracking-tight">Carousel Pro</h1>
        </div>

        <div className="flex-1 overflow-y-auto p-6 no-scrollbar">
          <EditorControls
            profile={profile}
            setProfile={setProfile}
            config={config}
            setConfig={setConfig}
            slides={slides}
            setSlides={setSlides}
            onBulkGenerate={handleBulkGenerate}
          />
        </div>

        <div className="p-6 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-black/20">
          <button
            onClick={exportAll}
            disabled={isExporting}
            className="w-full bg-[#1d9bf0] hover:bg-[#1a8cd8] text-white py-4 rounded-2xl font-bold text-lg transition-all shadow-lg hover:shadow-[#1d9bf0]/30 active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-3"
          >
            {isExporting ? (
              <>
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
                Exportando...
              </>
            ) : (
              'Exportar Carrossel'
            )}
          </button>
        </div>
      </aside>

      {/* Main Preview Area - Center/Right */}
      <main className="flex-1 overflow-y-auto overflow-x-hidden p-12 flex flex-col items-center gap-16 no-scrollbar bg-slate-100 dark:bg-[#10171e]">
        <div className="w-full max-w-4xl space-y-24">
          {slides.map((slide, index) => (
            <div key={slide.id} className="flex flex-col items-center group relative">
              <div className="absolute -left-16 top-1/2 -translate-y-1/2 text-slate-300 dark:text-slate-700 text-6xl font-black italic select-none">
                {String(index + 1).padStart(2, '0')}
              </div>
              <div ref={el => cardRefs.current[index] = el} className="shadow-[0_40px_100px_-20px_rgba(0,0,0,0.3)] dark:shadow-[0_40px_100px_-20px_rgba(0,0,0,0.8)] rounded-xl overflow-hidden">
