import React, { useState } from 'react';
import { ProfileInfo, Slide, CarouselConfig } from '../types';

interface Props {
  profile: ProfileInfo;
  setProfile: (p: ProfileInfo) => void;
  config: CarouselConfig;
  setConfig: (c: CarouselConfig) => void;
  slides: Slide[];
  setSlides: (s: Slide[]) => void;
  onBulkGenerate: (text: string) => void;
}

const EditorControls: React.FC<Props> = ({
  profile, setProfile, config, setConfig, slides, setSlides, onBulkGenerate
}) => {
  const [isRecording, setIsRecording] = useState(false);
  const [bulkText, setBulkText] = useState('');

  const startRecording = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.lang = 'pt-BR';
    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);
    recognition.onresult = (e: any) => {
      const transcript = e.results[0][0].transcript;
      setBulkText(prev => prev + (prev ? '\n\n' : '') + transcript);
    };
    recognition.start();
  };

  const handleGenerateClick = () => {
    onBulkGenerate(bulkText);
  };

  return (
    <div className="space-y-10">
      {/* 1. Profile Section */}
      <section className="space-y-4">
        <label className="text-[11px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Perfil Profissional</label>
        <div className="flex gap-4 p-4 rounded-2xl bg-slate-50 dark:bg-black/20 border border-slate-100 dark:border-slate-800">
          <div className="relative group shrink-0">
             <img src={profile.avatar} className="w-14 h-14 rounded-full object-cover border-2 border-[#1d9bf0]" alt="avatar" />
             <input
                type="file"
                className="absolute inset-0 opacity-0 cursor-pointer"
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) setProfile({ ...profile, avatar: URL.createObjectURL(file) });
                }}
              />
          </div>
          <div className="flex-1 space-y-1">
            <input
              type="text"
              value={profile.name}
              onChange={(e) => setProfile({ ...profile, name: e.target.value })}
              className="w-full bg-transparent border-none outline-none font-bold text-sm"
              placeholder="Nome Exibido"
            />
            <input
              type="text"
              value={profile.handle}
              onChange={(e) => setProfile({ ...profile, handle: e.target.value })}
              className="w-full bg-transparent border-none outline-none text-xs text-slate-500 font-medium"
              placeholder="@seu_usuario"
            />
          </div>
        </div>
      </section>

      {/* 2. Bulk Content Section */}
      <section className="space-y-4">
        <div className="flex justify-between items-center">
          <label className="text-[11px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Gerador Mágico</label>
          <button
            onClick={startRecording}
            className={`flex items-center gap-2 text-[10px] font-bold uppercase transition-all px-3 py-1 rounded-full ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-100 dark:bg-slate-800 text-slate-500'}`}
          >
            <div className={`w-2 h-2 rounded-full ${isRecording ? 'bg-white' : 'bg-red-500'}`} />
            {isRecording ? 'Ouvindo...' : 'Voz para Texto'}
          </button>
        </div>
        <div className="relative">
          <textarea
            value={bulkText}
            onChange={(e) => setBulkText(e.target.value)}
            className="w-full h-48 p-5 rounded-2xl bg-slate-50 dark:bg-black/40 border border-slate-100 dark:border-slate-800 outline-none focus:ring-2 focus:ring-[#1d9bf0]/20 transition-all text-sm resize-none no-scrollbar font-medium leading-relaxed"
            placeholder="Dite ou digite seu conteúdo aqui... Use dois espaços de linha para criar um novo card."
          />
        </div>
        <button
          onClick={handleGenerateClick}
          className="w-full py-3 bg-slate-900 dark:bg-white dark:text-slate-900 text-white rounded-xl font-black text-sm uppercase tracking-wider hover:opacity-90 transition active:scale-[0.98]"
        >
          Gerar Todos os Cards
        </button>
      </section>

      {/* 3. CTA & Styles */}
      <section className="space-y-6 pt-6 border-t border-slate-100 dark:border-slate-800">
        <div className="space-y-4">
          <label className="text-[11px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Chamada para Ação (CTA)</label>
          <div className="grid grid-cols-2 gap-2">
            {['Seguir', 'Comentar', 'Compartilhar', 'Salvar'].map(opt => (
              <button
                key={opt}
                onClick={() => setConfig({...config, cta: opt})}
                className={`py-2 text-[11px] font-bold rounded-lg border transition ${config.cta === opt ? 'bg-[#1d9bf0] text-white border-[#1d9bf0]' : 'border-slate-100 dark:border-slate-800 text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800'}`}
              >
                {opt}
              </button>
            ))}
          </div>
          <input
            type="text"
            value={config.cta}
            onChange={(e) => setConfig({ ...config, cta: e.target.value })}
            className="w-full p-3 rounded-xl bg-slate-50 dark:bg-black/20 border border-slate-100 dark:border-slate-800 outline-none text-xs font-bold"
            placeholder="Ou digite outra CTA..."
          />
        </div>

        <div className="space-y-4">
          <label className="text-[11px] font-black uppercase tracking-widest text-slate-400 dark:text-slate-500">Ajustes Visuais</label>
          <div className="p-4 rounded-2xl bg-slate-50 dark:bg-black/20 border border-slate-100 dark:border-slate-800 space-y-6">
            <div className="space-y-2">
              <div className="flex justify-between text-[10px] font-bold text-slate-400 uppercase">
                <span>Tamanho da Fonte</span>
                <span>{config.fontSize}px</span>
              </div>
              <input
                type="range"
                min="32"
                max="100"
                value={config.fontSize}
                onChange={(e) => setConfig({ ...config, fontSize: parseInt(e.target.value) })}
                className="w-full h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full appearance-none cursor-pointer accent-[#1d9bf0]"
              />
            </div>

            <div className="flex gap-2">
              <button
                onClick={() => setConfig({ ...config, theme: 'light' })}
                className={`flex-1 py-2 text-[10px] font-black rounded-lg transition border ${config.theme === 'light' ? 'bg-white border-[#1d9bf0] text-[#1d9bf0]' : 'bg-transparent border-slate-200 dark:border-slate-800 text-slate-400'}`}
              >
                MODO CLARO
              </button>
              <button
                onClick={() => setConfig({ ...config, theme: 'dark' })}
                className={`flex-1 py-2 text-[10px] font-black rounded-lg transition border ${config.theme === 'dark' ? 'bg-[#15202b] border-[#1d9bf0] text-white' : 'bg-transparent border-slate-200 dark:border-slate-800 text-slate-400'}`}
              >
                MODO ESCURO
              </button>
            </div>
          </div>
        </div>
      </section>

      <div className="pt-4 text-center">
        <p className="text-[10px] text-slate-300 dark:text-slate-600 font-medium">Use tags HTML como &lt;b&gt;, &lt;u&gt;, &lt;i&gt; e &lt;mark&gt; para estilizar.</p>
      </div>
    </div>
  );
};

