      default:
        content = `<div class="flex flex-col items-center w-full gap-10">
                  <div class="text-[140px]">📣</div>
                  <div class="text-[72px] font-black tracking-tight leading-tight text-center px-10">
                    ${config.cta}
                  </div>
                </div>`;
    }
    setCtaContent(content);
  }, [config.cta, profile.handle]);

  const handleBulkGenerate = (text: string) => {
    const parts = text.split(/\n\n+/).filter(p => p.trim().length > 0);
    if (parts.length === 0) return;

    const newSlides = parts.map((content) => ({
      id: Math.random().toString(36).substr(2, 9),
      content: content.trim().replace(/\n/g, '<br>')
    }));
    setSlides(newSlides);
    setActiveCardIndex(0);
    if (scrollRef.current) scrollRef.current.scrollLeft = 0;
  };

  const scrollToIndex = (index: number) => {
    if (scrollRef.current) {
      const container = scrollRef.current;
      const cardWidth = container.querySelector('.card-container-fixed')?.clientWidth || 0;
      const margin = 80; // Total horizontal margin
      container.scrollTo({
        left: index * (cardWidth + margin),
        behavior: 'smooth'
      });
      setActiveCardIndex(index);
    }
  };

  const handleScroll = () => {
    if (scrollRef.current) {
      const container = scrollRef.current;
      const cardWidth = container.querySelector('.card-container-fixed')?.clientWidth || 1;
      const margin = 80;
      const index = Math.round(container.scrollLeft / (cardWidth + margin));
      setActiveCardIndex(index);
    }
  };

  const exportAll = async () => {
    setIsExporting(true);
    try {
      for (let i = 0; i <= slides.length; i++) {
        const node = cardRefs.current[i];
        if (node) {
          const dataUrl = await toPng(node, {
            canvasWidth: 1080,
            canvasHeight: 1350,
            pixelRatio: 1,
            style: {
              transform: 'scale(1)',
              margin: '0',
            }
          });
          const link = document.createElement('a');
          link.download = `card-${i + 1}.png`;
          link.href = dataUrl;
          link.click();
          await new Promise(r => setTimeout(r, 400));
        }
      }
    } catch (err) {
      console.error('Export error:', err);
      alert('Erro ao exportar. Tente novamente.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className={`flex h-screen w-screen transition-colors duration-300 ${config.theme === 'dark' ? 'dark bg-[#10171e] text-white' : 'bg-slate-50 text-slate-900'}`}>
      {/* Sidebar */}
      <aside className="w-[400px] h-full flex flex-col border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-[#15202b] shadow-2xl z-30 overflow-hidden shrink-0">
        <div className="p-6 flex items-center gap-4 border-b border-slate-100 dark:border-slate-800">
          <div className="bg-[#1d9bf0] p-2.5 rounded-xl shadow-lg shadow-[#1d9bf0]/30">
             <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 24 24">
                <path d="M23.643 4.937c-.835.37-1.732.62-2.675.733a4.67 4.67 0 0 0 2.048-2.578 9.3 9.3 0 0 1-2.958 1.13 4.66 4.66 0 0 0-7.938 4.25 13.217 13.217 0 0 1-9.597-4.863 4.66 4.66 0 0 0 1.44 6.22 4.623 4.623 0 0 1-2.112-.583v.06a4.66 4.66 0 0 0 3.737 4.568 4.692 4.692 0 0 1-2.104.08 4.661 4.661 0 0 0 4.352 3.234 9.348 9.348 0 0 1-5.786 1.995 9.5 9.5 0 0 1-1.112-.065 13.175 13.175 0 0 0 7.14 2.093c8.57 0 13.255-7.098 13.255-13.254 0-.2-.005-.402-.014-.602a9.47 9.47 0 0 0 2.323-2.41z"></path>
             </svg>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none">Carousel Pro</h1>
            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">Twitter Edition</p>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-8 no-scrollbar">
          <EditorControls
            profile={profile}
            setProfile={setProfile}
            config={config}
            setConfig={setConfig}
            slides={slides}
            setSlides={setSlides}
            onBulkGenerate={handleBulkGenerate}
          />
        </div>

        <div className="p-8 border-t border-slate-100 dark:border-slate-800 bg-slate-50/80 dark:bg-black/20 backdrop-blur-sm">
          <button
            onClick={exportAll}
            disabled={isExporting}
            className="w-full bg-[#1d9bf0] hover:bg-[#1a8cd8] text-white py-4.5 rounded-2xl font-black text-lg transition-all shadow-xl shadow-[#1d9bf0]/20 active:scale-[0.98] disabled:opacity-50 flex items-center justify-center gap-3"
          >
            {isExporting ? (
              <><div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div> Processando...</>
            ) : (
              'Exportar Carrossel'
            )}
          </button>
        </div>
      </aside>

      {/* Main Preview Area */}
      <main className="flex-1 flex flex-col items-center justify-center workspace-grid bg-slate-100 dark:bg-[#10171e] relative overflow-hidden">
        {/* Navigation Buttons */}
        <button 
          onClick={() => scrollToIndex(Math.max(0, activeCardIndex - 1))}
          className="absolute left-8 top-1/2 -translate-y-1/2 z-20 p-4 bg-white/80 dark:bg-gray-800/80 rounded-full shadow-2xl hover:scale-110 transition active:scale-95 disabled:opacity-30 backdrop-blur-md border border-white/20"
          disabled={activeCardIndex === 0}
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
        </button>

        <button 
          onClick={() => scrollToIndex(Math.min(slides.length, activeCardIndex + 1))}
          className="absolute right-8 top-1/2 -translate-y-1/2 z-20 p-4 bg-white/80 dark:bg-gray-800/80 rounded-full shadow-2xl hover:scale-110 transition active:scale-95 disabled:opacity-30 backdrop-blur-md border border-white/20"
          disabled={activeCardIndex === slides.length}
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 5l7 7-7 7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
        </button>

        <div 
          ref={scrollRef}
          onScroll={handleScroll}
          className="flex items-center carousel-container h-full w-full overflow-x-auto no-scrollbar"
        >
          {slides.map((slide, index) => (
            <div key={slide.id} className={`card-container-fixed ${activeCardIndex === index ? 'active-card' : ''}`}>
              <div className="relative group">
                <div className="absolute -left-12 -top-12 text-slate-300 dark:text-slate-800 text-[80px] font-black italic select-none leading-none -z-10 opacity-30 group-hover:opacity-100 transition-opacity">
                  {String(index + 1).padStart(2, '0')}
                </div>
                <div 
                  ref={el => cardRefs.current[index] = el} 
                  className="card-preview-wrapper shadow-[0_50px_100px_-20px_rgba(0,0,0,0.25)] dark:shadow-[0_50px_100px_-20px_rgba(0,0,0,0.6)] rounded-2xl overflow-hidden"
                >
                  <CarouselCard
                    slide={slide}
                    profile={profile}
                    config={config}
                    onContentChange={(val) => {
                      const next = [...slides];
                      next[index].content = val;
                      setSlides(next);
                    }}
                  />
                </div>
              </div>
            </div>
          ))}

          {/* CTA Card - Now fully editable */}
          <div className={`card-container-fixed ${activeCardIndex === slides.length ? 'active-card' : ''}`}>
            <div className="relative group">
              <div className="absolute -left-12 -top-12 text-slate-300 dark:text-slate-800 text-[80px] font-black italic select-none leading-none -z-10 opacity-30 group-hover:opacity-100 transition-opacity">
                CTA
              </div>
              <div 
                ref={el => cardRefs.current[slides.length] = el} 
                className="card-preview-wrapper shadow-[0_50px_100px_-20px_rgba(0,0,0,0.25)] dark:shadow-[0_50px_100px_-20px_rgba(0,0,0,0.6)] rounded-2xl overflow-hidden"
              >
                <CarouselCard
                  slide={{ id: 'cta', content: ctaContent }}
                  profile={profile}
                  config={config}
                  onContentChange={(val) => setCtaContent(val)}
                />
              </div>
            </div>
          </div>
        </div>

        {/* Navigation Indicator Hint */}
        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex flex-col items-center gap-4">
           <div className="flex gap-2">
             {[...Array(slides.length + 1)].map((_, i) => (
               <div 
                 key={i} 
                 onClick={() => scrollToIndex(i)}
                 className={`h-2 rounded-full transition-all cursor-pointer ${activeCardIndex === i ? 'w-8 bg-[#1d9bf0]' : 'w-2 bg-slate-300 dark:bg-slate-700'}`} 
               />
             ))}
           </div>
           <div className="flex items-center gap-3 bg-white/80 dark:bg-black/30 backdrop-blur-md px-6 py-3 rounded-full border border-white/20 shadow-lg">
              <span className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-500">Card {activeCardIndex + 1} de {slides.length + 1}</span>
           </div>
        </div>
      </main>
    </div>
  );
};

export default App;

