import React, { useState, useRef, useEffect } from 'react';
import { ProfileInfo, Slide, CarouselConfig } from './types';
import CarouselCard from './components/CarouselCard';
import EditorControls from './components/EditorControls';
import { toPng } from 'html-to-image';
import { GoogleGenAI, Type } from "@google/genai";

const App: React.FC = () => {
  const [profile, setProfile] = useState<ProfileInfo>({
    name: 'Grupo Decisivo',
    handle: '@grupodecisivo_',
    avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=decisivo'
  });

  const [slides, setSlides] = useState<Slide[]>([
    { id: '1', content: 'Transforme seus pensamentos em carrosséis profissionais no estilo <b>Twitter</b>.' },
    { id: '2', content: 'O conteúdo é automaticamente centralizado na zona de segurança para o <u>Instagram</u>.' },
    { id: '3', content: 'Use o menu lateral para ditar seu texto e gerar todos os cards de uma vez.' }
  ]);

  const [ctaContent, setCtaContent] = useState('');
  const [config, setConfig] = useState<CarouselConfig>({
    theme: 'light',
    fontSize: 48,
    cta: 'Seguir'
  });

  const [activeCardIndex, setActiveCardIndex] = useState(0);
  const [isExporting, setIsExporting] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const cardRefs = useRef<(HTMLDivElement | null)[]>([]);

  // Update CTA Content contextually when config.cta changes
  useEffect(() => {
    const firstSlideText = slides[0]?.content.replace(/<[^>]*>/g, '').substring(0, 30) || 'esse conteúdo';
    const handle = profile.handle;

    let content = '';
    const iconSize = '2.5em';
    const titleSize = '1.5em';

    switch (config.cta) {
      case 'Seguir':
        content = `<div class="flex flex-col items-center w-full gap-8">
                  <div style="font-size: ${iconSize}">🚀</div>
                  <div style="font-size: ${titleSize}" class="font-black tracking-tight leading-tight text-center px-10">
                    Gostou de saber mais sobre <span class="text-[#1d9bf0]">${firstSlideText}...</span>?<br>
                    Siga <span class="text-[#1d9bf0]">${handle}</span> para não perder as próximas dicas!
                  </div>
                </div>`;
        break;
      case 'Comentar':
        content = `<div class="flex flex-col items-center w-full gap-8">
                  <div style="font-size: ${iconSize}">💬</div>
                  <div style="font-size: ${titleSize}" class="font-black tracking-tight leading-tight text-center px-10">
                    Qual sua maior dúvida sobre isso?<br>
                    <span class="text-[#1d9bf0]">Comente aqui embaixo</span> e vamos conversar!
                  </div>
                </div>`;
        break;
      case 'Compartilhar':
        content = `<div class="flex flex-col items-center w-full gap-8">
                  <div style="font-size: ${iconSize}">✈️</div>
                  <div style="font-size: ${titleSize}" class="font-black tracking-tight leading-tight text-center px-10">
                    Conhece alguém que precisa ver isso?<br>
                    <span class="text-[#1d9bf0]">Compartilhe agora</span> e ajude essa pessoa!
                  </div>
                </div>`;
        break;
      case 'Salvar':
        content = `<div class="flex flex-col items-center w-full gap-8">
                  <div style="font-size: ${iconSize}">🔖</div>
                  <div style="font-size: ${titleSize}" class="font-black tracking-tight leading-tight text-center px-10">
                    Dica de ouro vale ouro!<br>
                    <span class="text-[#1d9bf0]">Salve esse post</span> para revisar quando precisar.
                  </div>
                </div>`;
        break;
      default:
        content = `<div class="flex flex-col items-center w-full gap-8">
                  <div style="font-size: ${iconSize}">📣</div>
                  <div style="font-size: ${titleSize}" class="font-black tracking-tight leading-tight text-center px-10">
                    ${config.cta}
                  </div>
                </div>`;
    }
    setCtaContent(content);
  }, [config.cta, profile.handle, slides]);

  // Handle AI Bulk Generation using Gemini API
  const handleBulkGenerate = async (text: string) => {
    if (!text.trim()) return;
    setIsGenerating(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Transforme o seguinte texto em um carrossel de 3 a 7 slides no estilo Twitter. 
        Mantenha as frases curtas, impactantes e use quebras de linha para legibilidade.
        O objetivo é ser viral e educativo.
        Retorne no formato JSON um array de strings (cada string é um slide).
        Texto base: "${text}"`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });

      const textOutput = response.text || "[]";
      const generatedSlides = JSON.parse(textOutput);
      if (Array.isArray(generatedSlides) && generatedSlides.length > 0) {
        const newSlides = generatedSlides.map((content: string) => ({
          id: Math.random().toString(36).substr(2, 9),
          content: content.replace(/\n/g, '<br>')
        }));
        setSlides(newSlides);
      } else {
        const parts = text.split(/\n\n+/).filter(p => p.trim().length > 0);
        setSlides(parts.map(p => ({ id: Math.random().toString(36).substr(2, 9), content: p.trim().replace(/\n/g, '<br>') })));
      }

      setActiveCardIndex(0);
      if (scrollRef.current) scrollRef.current.scrollLeft = 0;
    } catch (err) {
      console.error("AI Generation failed:", err);
      const parts = text.split(/\n\n+/).filter(p => p.trim().length > 0);
      setSlides(parts.map(p => ({ id: Math.random().toString(36).substr(2, 9), content: p.trim().replace(/\n/g, '<br>') })));
    } finally {
      setIsGenerating(false);
    }
  };

  const scrollToIndex = (index: number) => {
    if (scrollRef.current) {
      const container = scrollRef.current;
      const cardWidth = container.querySelector('.card-container-fixed')?.clientWidth || 0;
      const margin = 80;
      container.scrollTo({
        left: index * (cardWidth + margin),
        behavior: 'smooth'
      });
      setActiveCardIndex(index);
    }
  };

  const handleScroll = () => {
    if (scrollRef.current) {
      const container = scrollRef.current;
      const cardWidth = container.querySelector('.card-container-fixed')?.clientWidth || 1;
      const margin = 80;
      const index = Math.round(container.scrollLeft / (cardWidth + margin));
      setActiveCardIndex(index);
    }
  };

  // Export all cards as high-resolution images
  const exportAll = async () => {
    setIsExporting(true);
    try {
      for (let i = 0; i <= slides.length; i++) {
        const node = cardRefs.current[i];
        if (node) {
          const dataUrl = await toPng(node, {
            canvasWidth: 1080,
            canvasHeight: 1350,
            pixelRatio: 1,
            style: {
              transform: 'scale(1)',
              margin: '0',
            }
          });
          const link = document.createElement('a');
          link.download = `card-${i + 1}.png`;
          link.href = dataUrl;
          link.click();
          await new Promise(r => setTimeout(r, 400));
        }
      }
    } catch (err) {
      console.error('Export error:', err);
      alert('Erro ao exportar. Tente novamente.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className={`min-h-screen ${config.theme === 'dark' ? 'bg-[#0f171e] text-white' : 'bg-[#f8fafc] text-slate-900'} font-sans transition-colors duration-500 overflow-hidden flex flex-col md:flex-row`}>
      {/* Sidebar Controls */}
      <div className="w-full md:w-[420px] h-screen overflow-y-auto border-r border-slate-200 dark:border-slate-800 p-8 no-scrollbar bg-white dark:bg-[#0b141a] shrink-0">
        <div className="flex items-center gap-3 mb-10">
          <div className="w-10 h-10 bg-[#1d9bf0] rounded-xl flex items-center justify-center shadow-lg shadow-[#1d9bf0]/30">
