  slide: Slide;
  profile: ProfileInfo;
  config: CarouselConfig;
  onContentChange: (content: string) => void;
}

const CarouselCard: React.FC<Props> = ({ slide, profile, config, onContentChange }) => {
  const isDark = config.theme === 'dark';

  return (
    <div
      style={{
        width: '1080px',
        height: '1350px',
        backgroundColor: isDark ? '#15202b' : '#ffffff',
        color: isDark ? '#ffffff' : '#000000',
        display: 'flex',
        flexDirection: 'column',
        position: 'relative',
        overflow: 'hidden',
        boxSizing: 'border-box'
      }}
    >
      <style>{`
        mark {
          background-color: ${config.highlightColor};
          color: inherit;
          padding: 0 4px;
          border-radius: 4px;
        }
      `}</style>

      {/* 1080x1080 Safe Content Zone */}
      <div
        style={{
          width: '1080px',
          height: '1080px',
          marginTop: '135px',
          marginBottom: '135px',
          padding: '160px 100px 140px 100px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          position: 'relative',
          boxSizing: 'border-box'
        }}
      >
        {/* Profile Header */}
        <div 
          className="absolute top-12 left-[100px] right-[100px] flex items-start gap-6 pointer-events-none"
          style={{ boxSizing: 'border-box' }}
        >
          <div 
            className="w-24 h-24 rounded-full border-4 overflow-hidden shrink-0 bg-slate-200"
            style={{ borderColor: isDark ? '#38444d' : '#f1f5f9' }}
          >
            <img
              src={profile.avatar}
              alt="Avatar"
              className="w-full h-full object-cover"
              onError={(e) => {
                e.currentTarget.src = 'https://api.dicebear.com/7.x/initials/svg?seed=' + profile.name;
              }}
            />
          </div>
          <div className="flex flex-col pt-2 overflow-hidden">
            <div className="flex items-center gap-3">
              <span className="text-[44px] font-black leading-tight tracking-tight truncate max-w-[700px]">{profile.name}</span>
              <svg className="w-9 h-9 text-[#1d9bf0] shrink-0" fill="currentColor" viewBox="0 0 24 24">
