            type: Type.OBJECT,
            properties: {
              slides: { type: Type.ARRAY, items: { type: Type.STRING } },
              bridge: { type: Type.STRING },
              caption: { type: Type.STRING }
            },
            required: ["slides", "bridge", "caption"]
          }
        }
      });

      const data = JSON.parse(response.text || "{}");
      if (data.slides) {
        setSlides(data.slides.map((c: string) => ({
          id: Math.random().toString(36).substr(2, 9),
          content: c
        })));
        if (data.bridge) setCtaBridge(data.bridge);
        if (data.caption) setCaption(data.caption);
      }
      setActiveCardIndex(0);
      if (scrollRef.current) scrollRef.current.scrollLeft = 0;
    } catch (err) {
      console.error("AI Gen error:", err);
      const manualSlides = text.split(/\n\n+/).filter(Boolean).map(c => ({ 
        id: Math.random().toString(36).substr(2, 9), 
        content: c.trim().replace(/\n/g, '<br>') 
      }));
      setSlides(manualSlides);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAIImageGeneration = async (prompt: string) => {
    if (!prompt.trim()) return;
    setIsGeneratingImage(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { imageConfig: { aspectRatio: "16:9" } }
      });

      let imageData = '';
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          imageData = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }

      if (imageData && activeCardIndex < slides.length) {
        const next = [...slides];
        next[activeCardIndex].image = imageData;
        setSlides(next);
      }
    } catch (err) {
      console.error("AI Image Gen error:", err);
      alert("Erro ao gerar imagem.");
    } finally {
      setIsGeneratingImage(false);
    }
  };

  const scrollToIndex = (index: number) => {
    if (scrollRef.current) {
      const cardWidth = scrollRef.current.querySelector('.card-container-fixed')?.clientWidth || 0;
      const gap = 80;
      scrollRef.current.scrollTo({
        left: index * (cardWidth + gap),
        behavior: 'smooth'
      });
      setActiveCardIndex(index);
    }
  };

  const handleScroll = () => {
    if (scrollRef.current) {
      const cardWidth = scrollRef.current.querySelector('.card-container-fixed')?.clientWidth || 1;
      const gap = 80;
      const index = Math.round(scrollRef.current.scrollLeft / (cardWidth + gap));
      setActiveCardIndex(index);
    }
  };

  const exportAll = async () => {
    setIsExporting(true);
    try {
      const firstSlideText = slides[0]?.content || 'carousel';
      const cleanName = firstSlideText
        .replace(/<[^>]*>/g, '')
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-z0-9]/gi, '_')
        .toLowerCase()
        .substring(0, 35)
        .replace(/^_+|_+$/g, '');

      const timestamp = new Date().toISOString().split('T')[0];
      const filePrefix = cleanName ? `${cleanName}_${timestamp}` : `carousel_${timestamp}`;

      for (let i = 0; i <= slides.length; i++) {
        const node = cardRefs.current[i];
        if (node) {
          const dataUrl = await toPng(node, {
            canvasWidth: 1080,
            canvasHeight: 1350,
            pixelRatio: 1.5,
            style: { transform: 'scale(1)', margin: '0' }
          });
          const link = document.createElement('a');
          link.download = `${filePrefix}_slide_${i + 1}.png`;
          link.href = dataUrl;
          link.click();
          await new Promise(r => setTimeout(r, 600));
        }
      }
    } catch (err) {
      alert('Erro ao exportar. Tente novamente.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className={`flex flex-col md:flex-row h-screen w-screen overflow-hidden transition-colors duration-500 ${config.theme === 'dark' ? 'bg-[#0f171e] text-white' : 'bg-[#f1f5f9] text-slate-900'}`}>
      {/* Sidebar */}
      <aside className="w-full md:w-[420px] h-full flex flex-col border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-[#0b141a] z-30 shadow-2xl shrink-0 overflow-y-auto no-scrollbar p-8">
        <div className="flex items-center gap-4 mb-10">
          <div className="bg-[#1d9bf0] p-2.5 rounded-2xl shadow-lg shadow-[#1d9bf0]/20">
             <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 24 24"><path d="M23.643 4.937c-.835.37-1.732.62-2.675.733.962-.576 1.7-1.49 2.048-2.578-.9.534-1.897.922-2.958 1.13-.85-.904-2.06-1.47-3.4-1.47-2.572 0-4.658 2.086-4.658 4.66 0 .364.042.718.12 1.06-3.873-.195-7.304-2.05-9.602-4.868-.4.69-.63 1.49-.63 2.342 0 1.616.823 3.043 2.072 3.878-.764-.025-1.482-.234-2.11-.583v.06c0 2.257 1.605 4.14 3.737 4.568-.392.106-.803.162-1.227.162-.3 0-.593-.028-.877-.082.593 1.85 2.313 3.198 4.352 3.234-1.595 1.25-3.604 1.995-5.786 1.995-.376 0-.747-.022-1.112-.065 2.062 1.323 4.51 2.093 7.14 2.093 8.57 0 13.255-7.098 13.255-13.254 0-.2-.005-.402-.014-.602.91-.658 1.7-1.477 2.323-2.41z"></path></svg>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none uppercase text-slate-900 dark:text-white">Carousel Studio</h1>
            <p className="text-[10px] font-bold text-[#1d9bf0] tracking-widest mt-1">Twitter Edition</p>
          </div>
        </div>

        <EditorControls
          profile={profile} setProfile={setProfile}
          config={config} setConfig={setConfig}
          slides={slides} setSlides={setSlides}
          prompts={prompts} setPrompts={setPrompts}
          onBulkGenerate={handleBulkGenerate}
          onGenerateImage={handleAIImageGeneration}
          activeCardIndex={activeCardIndex}
          isGeneratingImage={isGeneratingImage}
          caption={caption}
          setCaption={setCaption}
        />

        <div className="mt-auto pt-8">
          <button
            onClick={exportAll}
            disabled={isExporting}
            className={`w-full py-5 rounded-2xl font-black text-sm uppercase tracking-widest flex items-center justify-center gap-3 shadow-xl transition-all ${isExporting ? 'bg-slate-100 text-slate-400' : 'bg-[#1d9bf0] text-white hover:bg-[#1a8cd8] active:scale-[0.98]'}`}
          >
            {isExporting ? (
              <><div className="w-5 h-5 border-2 border-slate-300 border-t-slate-500 rounded-full animate-spin" /> EXPORTANDO</>
            ) : 'BAIXAR PNG'}
          </button>
        </div>
      </aside>

      {/* Workspace */}
      <main className="flex-1 relative flex flex-col workspace-grid overflow-hidden">
        {/* Navigation Arrows */}
        <button 
          onClick={() => scrollToIndex(activeCardIndex - 1)}
          className="absolute left-8 top-1/2 -translate-y-1/2 z-20 p-5 bg-white/80 dark:bg-slate-800/80 rounded-full shadow-2xl backdrop-blur-xl border border-white/20 hover:scale-110 active:scale-90 transition disabled:opacity-0"
          disabled={activeCardIndex === 0}
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
        </button>

        <button 
          onClick={() => scrollToIndex(activeCardIndex + 1)}
          className="absolute right-8 top-1/2 -translate-y-1/2 z-20 p-5 bg-white/80 dark:bg-slate-800/80 rounded-full shadow-2xl backdrop-blur-xl border border-white/20 hover:scale-110 active:scale-90 transition disabled:opacity-0"
          disabled={activeCardIndex === slides.length}
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 5l7 7-7 7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
        </button>

        <div 
          ref={scrollRef}
          onScroll={handleScroll}
          className="carousel-viewport w-full h-full flex items-center gap-20 overflow-x-auto no-scrollbar px-[calc(50vw-216px)] md:px-[calc(50vw-270px-210px)]"
        >
          {slides.map((slide, index) => (
            <div key={slide.id} className={`card-container-fixed ${activeCardIndex === index ? 'active-card' : ''}`}>
               <div ref={el => cardRefs.current[index] = el} className="card-preview-wrapper rounded-[40px] overflow-hidden">
                  <CarouselCard
                    slide={slide}
                    profile={profile}
                    config={config}
                    onContentChange={(val) => {
                      const next = [...slides];
                      next[index].content = val;
                      setSlides(next);
                    }}
                  />
               </div>
            </div>
          ))}

          {/* Connected CTA Card */}
          <div className={`card-container-fixed ${activeCardIndex === slides.length ? 'active-card' : ''}`}>
             <div ref={el => cardRefs.current[slides.length] = el} className="card-preview-wrapper rounded-[40px] overflow-hidden">
                <CarouselCard
                  slide={{ id: 'cta', content: ctaContent }}
                  profile={profile}
                  config={config}
                  onContentChange={(val) => setCtaContent(val)}
                />
             </div>
          </div>
        </div>

        {/* Bottom Pagination */}
        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex flex-col items-center gap-6">
           <div className="flex gap-2">
             {[...Array(slides.length + 1)].map((_, i) => (
               <div 
                 key={i} 
                 onClick={() => scrollToIndex(i)}
                 className={`h-2.5 rounded-full transition-all cursor-pointer ${activeCardIndex === i ? 'w-10 bg-[#1d9bf0]' : 'w-2.5 bg-slate-300 dark:bg-slate-700 hover:bg-slate-400'}`} 
               />
             ))}
           </div>
           <div className="bg-white/90 dark:bg-black/30 backdrop-blur-xl border border-white/20 px-8 py-2 rounded-full shadow-2xl">
              <span className="text-[10px] font-black uppercase tracking-[0.3em] opacity-60 text-slate-900 dark:text-white">Card {activeCardIndex + 1} de {slides.length + 1}</span>
           </div>
        </div>
      </main>

      {/* Loading Overlay */}
      {(isGenerating || isGeneratingImage) && (
        <div className="fixed inset-0 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md z-[100] flex flex-col items-center justify-center">
           <div className="w-20 h-20 border-4 border-[#1d9bf0]/20 border-t-[#1d9bf0] rounded-full animate-spin mb-6" />
           <p className="font-black text-sm uppercase tracking-widest animate-pulse text-slate-900 dark:text-white">
             {isGeneratingImage ? "Pincelando sua imagem..." : "Destilando conhecimento..."}
           </p>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ProfileInfo, Slide, CarouselConfig } from '../types';

interface Props {
  profile: ProfileInfo;
  setProfile: (p: ProfileInfo) => void;
  config: CarouselConfig;
  setConfig: (c: CarouselConfig) => void;
  slides: Slide[];
  setSlides: (s: Slide[]) => void;
  prompts: { technical: string; tone: string };
  setPrompts: (p: { technical: string; tone: string }) => void;
  onBulkGenerate: (text: string) => void;
  onGenerateImage: (prompt: string) => void;
  activeCardIndex: number;
  isGeneratingImage: boolean;
  caption: string;
  setCaption: (c: string) => void;
}

const EditorControls: React.FC<Props> = ({
  profile, setProfile, config, setConfig, slides, setSlides, prompts, setPrompts, onBulkGenerate, onGenerateImage, activeCardIndex, isGeneratingImage, caption, setCaption
}) => {
  const [isRecording, setIsRecording] = useState(false);
  const [bulkText, setBulkText] = useState('');
  const [showPrompts, setShowPrompts] = useState(false);
  const [aiImagePrompt, setAiImagePrompt] = useState('');
  const [copied, setCopied] = useState(false);

  const startRecording = () => {
    const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
    if (!SpeechRecognition) return;

    const recognition = new SpeechRecognition();
    recognition.lang = 'pt-BR';
    recognition.onstart = () => setIsRecording(true);
    recognition.onend = () => setIsRecording(false);
    recognition.onresult = (e: any) => {
      const transcript = e.results[0][0].transcript;
      setBulkText(prev => prev + (prev ? '\n\n' : '') + transcript);
    };
    recognition.start();
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file && activeCardIndex < slides.length) {
      const reader = new FileReader();
      reader.onload = (event) => {
        const next = [...slides];
        next[activeCardIndex].image = event.target?.result as string;
        setSlides(next);
      };
      reader.readAsDataURL(file);
    }
  };

  const removeImage = () => {
    if (activeCardIndex < slides.length) {
      const next = [...slides];
      delete next[activeCardIndex].image;
      setSlides(next);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(caption);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div className="space-y-10">
      {/* 1. Profile Section */}
      <section className="space-y-4">
        <label className="text-[11px] font-black uppercase tracking-widest text-slate-600 dark:text-zinc-300">Perfil Profissional</label>
        <div className="flex gap-4 p-4 rounded-2xl bg-slate-50 dark:bg-black/40 border border-slate-100 dark:border-slate-800 transition-colors">
          <div className="relative group shrink-0">
             <img src={profile.avatar} className="w-14 h-14 rounded-full object-cover border-2 border-[#1d9bf0]" alt="avatar" />
             <input
                type="file"
                className="absolute inset-0 opacity-0 cursor-pointer"
                onChange={(e) => {
                  const file = e.target.files?.[0];
                  if (file) setProfile({ ...profile, avatar: URL.createObjectURL(file) });
                }}
              />
          </div>
          <div className="flex-1 space-y-1">
            <input
              type="text"
              value={profile.name}
              onChange={(e) => setProfile({ ...profile, name: e.target.value })}
              className="w-full bg-transparent border-none outline-none font-bold text-sm text-slate-900 dark:text-white placeholder:text-slate-400 dark:placeholder:text-zinc-500"
              placeholder="Nome Exibido"
            />
            <input
              type="text"
              value={profile.handle}
              onChange={(e) => setProfile({ ...profile, handle: e.target.value })}
              className="w-full bg-transparent border-none outline-none text-xs text-slate-500 dark:text-zinc-400 font-medium placeholder:text-slate-400 dark:placeholder:text-zinc-600"
              placeholder="@seu_usuario"
            />
          </div>
        </div>
      </section>

      {/* 2. Bulk Content & Prompt Settings */}
      <section className="space-y-4">
        <div className="flex justify-between items-center">
          <label className="text-[11px] font-black uppercase tracking-widest text-slate-600 dark:text-zinc-300">Gerador Mágico</label>
          <button 
            onClick={() => setShowPrompts(!showPrompts)}
            className="text-[10px] font-bold text-[#1d9bf0] uppercase tracking-tighter hover:underline"
          >
            {showPrompts ? 'Fechar Prompts' : 'Configurar IA'}
          </button>
        </div>

        {showPrompts && (
          <div className="space-y-4 p-5 rounded-2xl bg-blue-50/50 dark:bg-blue-900/10 border border-blue-100 dark:border-blue-900/30">
            <div className="space-y-2">
              <label className="text-[9px] font-black uppercase tracking-widest text-blue-700 dark:text-blue-400">Prompt Técnico</label>
              <textarea
                value={prompts.technical}
                onChange={(e) => setPrompts({ ...prompts, technical: e.target.value })}
                className="w-full h-20 p-3 text-[11px] bg-white dark:bg-black/30 border border-blue-200 dark:border-blue-800 rounded-lg outline-none resize-none text-slate-900 dark:text-white"
              />
            </div>
            <div className="space-y-2">
              <label className="text-[9px] font-black uppercase tracking-widest text-blue-700 dark:text-blue-400">Tom de Voz</label>
              <textarea
                value={prompts.tone}
                onChange={(e) => setPrompts({ ...prompts, tone: e.target.value })}
                className="w-full h-20 p-3 text-[11px] bg-white dark:bg-black/30 border border-blue-200 dark:border-blue-800 rounded-lg outline-none resize-none text-slate-900 dark:text-white"
              />
            </div>
          </div>
        )}

        <div className="relative">
          <textarea
            value={bulkText}
            onChange={(e) => setBulkText(e.target.value)}
            className="w-full h-40 p-5 rounded-2xl bg-slate-50 dark:bg-black/40 border border-slate-100 dark:border-slate-800 outline-none focus:ring-2 focus:ring-[#1d9bf0]/20 transition-all text-sm resize-none no-scrollbar font-medium leading-relaxed text-slate-900 dark:text-white placeholder:text-slate-400 dark:placeholder:text-zinc-500"
            placeholder="Dite ou digite seu conteúdo bruto aqui..."
          />
          <button
            onClick={startRecording}
            className={`absolute bottom-4 right-4 p-2 rounded-full transition-all ${isRecording ? 'bg-red-500 text-white animate-pulse' : 'bg-slate-200 dark:bg-slate-700 text-slate-600 dark:text-zinc-400'}`}
          >
            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M19 11a7 7 0 01-7 7m0 0a7 7 0 01-7-7m7 7v4m0 0H8m4 0h4m-4-8a3 3 0 01-3-3V5a3 3 0 116 0v6a3 3 0 01-3 3z" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"></path></svg>
          </button>
        </div>
        <button
          onClick={() => onBulkGenerate(bulkText)}
          className="w-full py-3 bg-slate-900 dark:bg-white dark:text-slate-900 text-white rounded-xl font-black text-sm uppercase tracking-wider hover:opacity-90 transition active:scale-[0.98]"
        >
          Gerar Carrossel Estratégico
        </button>
      </section>

      {/* 2.5 Image Content Section */}
      <section className="space-y-4 pt-6 border-t border-slate-100 dark:border-slate-800">
         <label className="text-[11px] font-black uppercase tracking-widest text-slate-600 dark:text-zinc-300">Mídia do Card Ativo</label>
         <div className="space-y-3">
            <div className="flex gap-2">
               <label className="flex-1 cursor-pointer flex items-center justify-center gap-2 py-3 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-xl hover:bg-slate-50 dark:hover:bg-slate-900 transition text-[10px] font-bold text-slate-500">
                  <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-8l-4-4m0 0L8 8m4-4v12" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"></path></svg>
                  UPLOAD
                  <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
               </label>
               {activeCardIndex < slides.length && slides[activeCardIndex].image && (
                 <button 
                  onClick={removeImage}
                  className="px-4 py-2 bg-red-50 text-red-500 rounded-xl font-bold text-[10px] hover:bg-red-100 transition"
                 >
                    REMOVER
                 </button>
               )}
            </div>

            <div className="space-y-2">
               <label className="text-[9px] font-black uppercase tracking-widest text-slate-400">Gerar com IA</label>
               <div className="flex gap-2">
                  <input 
                    type="text" 
                    value={aiImagePrompt}
                    onChange={(e) => setAiImagePrompt(e.target.value)}
                    placeholder="Descreva a imagem..."
                    className="flex-1 p-3 bg-slate-50 dark:bg-black/20 border border-slate-100 dark:border-slate-800 rounded-xl text-xs text-slate-900 dark:text-white outline-none"
                  />
                  <button 
                    disabled={isGeneratingImage || !aiImagePrompt.trim()}
                    onClick={() => onGenerateImage(aiImagePrompt)}
                    className="p-3 bg-[#1d9bf0] text-white rounded-xl disabled:opacity-50"
                  >
                     <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z"></path></svg>
                  </button>
               </div>
            </div>
         </div>
      </section>

      {/* New Caption Section */}
      {caption && (
        <section className="space-y-4 pt-6 border-t border-slate-100 dark:border-slate-800">
          <div className="flex justify-between items-center">
            <label className="text-[11px] font-black uppercase tracking-widest text-slate-600 dark:text-zinc-300">Legenda do Post</label>
            <button 
              onClick={copyToClipboard}
              className={`text-[10px] font-black uppercase tracking-tighter px-3 py-1 rounded-full transition-all ${copied ? 'bg-green-500 text-white' : 'bg-slate-100 dark:bg-slate-800 text-slate-500 dark:text-zinc-400 hover:bg-[#1d9bf0] hover:text-white'}`}
            >
              {copied ? 'COPIADO!' : 'COPIAR'}
            </button>
          </div>
          <textarea
            value={caption}
            onChange={(e) => setCaption(e.target.value)}
            className="w-full h-48 p-4 rounded-xl bg-slate-50 dark:bg-black/20 border border-slate-100 dark:border-slate-800 outline-none text-xs font-medium leading-relaxed text-slate-900 dark:text-white resize-none no-scrollbar"
          />
        </section>
      )}

      {/* 3. CTA & Styles */}
      <section className="space-y-6 pt-6 border-t border-slate-100 dark:border-slate-800">
        <div className="space-y-4">
          <label className="text-[11px] font-black uppercase tracking-widest text-slate-600 dark:text-zinc-300">Chamada para Ação (CTA)</label>
          <div className="grid grid-cols-2 gap-2">
            {['Seguir', 'Comentar', 'Compartilhar', 'Salvar'].map(opt => (
              <button
                key={opt}
                onClick={() => setConfig({...config, cta: opt})}
                className={`py-2 text-[11px] font-bold rounded-lg border transition ${config.cta === opt ? 'bg-[#1d9bf0] text-white border-[#1d9bf0]' : 'border-slate-200 dark:border-slate-800 text-slate-500 dark:text-zinc-400 hover:bg-slate-50 dark:hover:bg-slate-800'}`}
              >
                {opt}
              </button>
            ))}
          </div>
          <input
            type="text"
            value={config.cta}
            onChange={(e) => setConfig({ ...config, cta: e.target.value })}
            className="w-full p-3 rounded-xl bg-slate-50 dark:bg-black/20 border border-slate-100 dark:border-slate-800 outline-none text-xs font-bold text-slate-900 dark:text-white placeholder:text-slate-400"
            placeholder="Ou digite outra CTA..."
          />
        </div>

        <div className="space-y-4">
          <label className="text-[11px] font-black uppercase tracking-widest text-slate-600 dark:text-zinc-300">Personalização Visual</label>
          <div className="p-5 rounded-2xl bg-slate-50 dark:bg-black/40 border border-slate-100 dark:border-slate-800 space-y-6">
            <div className="space-y-2">
              <div className="flex justify-between text-[10px] font-bold text-slate-500 dark:text-zinc-400 uppercase">
                <span>Tamanho da Fonte</span>
                <span className="text-slate-900 dark:text-white">{config.fontSize}px</span>
              </div>
              <input
                type="range" min="32" max="100" value={config.fontSize}
                onChange={(e) => setConfig({ ...config, fontSize: parseInt(e.target.value) })}
                className="w-full h-1.5 bg-slate-200 dark:bg-slate-700 rounded-full appearance-none cursor-pointer accent-[#1d9bf0]"
              />
            </div>

            <div className="space-y-2">
              <div className="flex justify-between text-[10px] font-bold text-slate-500 dark:text-zinc-400 uppercase">
                <span>Cor do Destaque (Mark)</span>
                <span className="uppercase text-[9px] font-black" style={{ color: config.highlightColor }}>{config.highlightColor}</span>
              </div>
              <div className="flex gap-2">
                {['#74ebd5', '#ffd93d', '#ff6b6b', '#6bc1ff', '#a8e6cf'].map(c => (
                  <button
                    key={c}
                    onClick={() => setConfig({ ...config, highlightColor: c })}
                    className={`w-6 h-6 rounded-full border-2 transition-transform ${config.highlightColor === c ? 'scale-125 border-white dark:border-white shadow-lg' : 'border-transparent hover:scale-110'}`}
                    style={{ backgroundColor: c }}
                  />
                ))}
                <input
                  type="color"
                  value={config.highlightColor}
                  onChange={(e) => setConfig({ ...config, highlightColor: e.target.value })}
                  className="w-6 h-6 p-0 rounded-full bg-transparent border-none cursor-pointer overflow-hidden shadow-sm"
                />
              </div>
            </div>

            <div className="flex gap-2">
              <button
                onClick={() => setConfig({ ...config, theme: 'light' })}
                className={`flex-1 py-2 text-[10px] font-black rounded-lg transition border ${config.theme === 'light' ? 'bg-white border-[#1d9bf0] text-[#1d9bf0]' : 'bg-transparent border-slate-300 dark:border-slate-800 text-slate-400 dark:text-zinc-500'}`}
              >
                MODO CLARO
              </button>
              <button
                onClick={() => setConfig({ ...config, theme: 'dark' })}
                className={`flex-1 py-2 text-[10px] font-black rounded-lg transition border ${config.theme === 'dark' ? 'bg-[#15202b] border-[#1d9bf0] text-white' : 'bg-transparent border-slate-300 dark:border-slate-800 text-slate-400 dark:text-zinc-500'}`}
              >
                MODO ESCURO
              </button>
            </div>
          </div>
        </div>
      </section>

      <div className="pt-4 text-center">
        <p className="text-[10px] text-slate-400 dark:text-zinc-600 font-medium tracking-tight">Potencializado por Google Gemini 3 Flash</p>
      </div>
    </div>
  );
};

export default EditorControls;

import React, { useState, useRef, useEffect } from 'react';
import { ProfileInfo, Slide, CarouselConfig } from './types';
import CarouselCard from './components/CarouselCard';
import EditorControls from './components/EditorControls';
import { toPng } from 'html-to-image';
import { GoogleGenAI, Type } from "@google/genai";

const App: React.FC = () => {
  const [profile, setProfile] = useState<ProfileInfo>({
    name: 'Grupo Decisivo',
    handle: '@grupodecisivo_',
    avatar: 'https://api.dicebear.com/7.x/avataaars/svg?seed=decisivo'
  });

  const [slides, setSlides] = useState<Slide[]>([
    { id: '1', content: 'Transforme seus pensamentos em carrosséis profissionais no estilo <b>Twitter</b>.' },
    { id: '2', content: 'O conteúdo é automaticamente centralizado na zona de segurança para o <u>Instagram</u>.' },
    { id: '3', content: 'Use o menu lateral para ditar seu texto e gerar todos os cards de uma vez.' }
  ]);

  const [caption, setCaption] = useState('');
  const [ctaContent, setCtaContent] = useState('');
  const [ctaBridge, setCtaBridge] = useState('Se este conteúdo te ajudou de alguma forma:');

  const [config, setConfig] = useState<CarouselConfig>({
    theme: 'light',
    fontSize: 48,
    cta: 'Seguir',
    highlightColor: '#74ebd5'
  });

  const [prompts, setPrompts] = useState({
    technical: 'Divida o conteúdo em uma sequência lógica de 4 a 7 slides. Cada slide deve fluir para o próximo como uma conversa. Use no máximo 180 caracteres por card.',
    tone: 'Persuasivo, autoritário, mas acessível. Estilo "thread" do Twitter.'
  });

  const [activeCardIndex, setActiveCardIndex] = useState(0);
  const [isExporting, setIsExporting] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isGeneratingImage, setIsGeneratingImage] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const cardRefs = useRef<(HTMLDivElement | null)[]>([]);

  // Update CTA Content with a natural bridge that feels like a conclusion
  useEffect(() => {
    const handle = profile.handle;
    const icon = config.cta === 'Seguir' ? '🚀' : config.cta === 'Comentar' ? '💬' : config.cta === 'Compartilhar' ? '✈️' : config.cta === 'Salvar' ? '🔖' : '📣';

    // The CTA card is a conclusion, not just a floating button
    const content = `<div style="margin-bottom: 32px;">${icon}</div><div style="font-size: 0.85em; opacity: 0.9; margin-bottom: 16px; font-weight: 500; line-height: 1.4;">${ctaBridge}</div><div style="font-size: 1.1em; line-height: 1.2;"><b>${config.cta} <u>${handle}</u></b><br>para dominar as próximas estratégias!</div>`;

    setCtaContent(content);
  }, [config.cta, profile.handle, ctaBridge]);

  const handleBulkGenerate = async (text: string) => {
    if (!text.trim()) return;
    setIsGenerating(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: `Aja como um estrategista de conteúdo viral. Crie um carrossel narrativo e a legenda do post sobre: "${text}".

        DIRETRIZES TÉCNICAS: ${prompts.technical}
        TOM DE VOZ: ${prompts.tone}

        ESTRUTURA OBRIGATÓRIA:
        - Os cards devem contar uma história ou processo passo a passo.
        - Use <b> para negrito, <u> para sublinhado e <mark> para palavras-chave.
        - A "bridge" deve ser a conclusão orgânica e o "gancho" final do conteúdo.
        - A "caption" deve ser uma legenda de alta conversão para Instagram, com um "hook" inicial forte, resumo do valor, emojis e hashtags relevantes.

        Retorne no formato JSON: { 
          "slides": ["...", "..."], 
          "bridge": "Frase de conexão", 
          "caption": "Legenda completa para o Instagram" 
        }`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              slides: { type: Type.ARRAY, items: { type: Type.STRING } },
              bridge: { type: Type.STRING },
              caption: { type: Type.STRING }
            },
            required: ["slides", "bridge", "caption"]
          }
        }
      });

      const data = JSON.parse(response.text || "{}");
      if (data.slides) {
        setSlides(data.slides.map((c: string) => ({
          id: Math.random().toString(36).substr(2, 9),
          content: c
        })));
        if (data.bridge) setCtaBridge(data.bridge);
        if (data.caption) setCaption(data.caption);
      }
      setActiveCardIndex(0);
      if (scrollRef.current) scrollRef.current.scrollLeft = 0;
    } catch (err) {
      console.error("AI Gen error:", err);
      const manualSlides = text.split(/\n\n+/).filter(Boolean).map(c => ({ 
        id: Math.random().toString(36).substr(2, 9), 
        content: c.trim().replace(/\n/g, '<br>') 
      }));
      setSlides(manualSlides);
    } finally {
      setIsGenerating(false);
    }
  };

  const handleAIImageGeneration = async (prompt: string) => {
    if (!prompt.trim()) return;
    setIsGeneratingImage(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: { parts: [{ text: prompt }] },
        config: { imageConfig: { aspectRatio: "16:9" } }
      });

      let imageData = '';
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          imageData = `data:image/png;base64,${part.inlineData.data}`;
          break;
        }
      }

      if (imageData && activeCardIndex < slides.length) {
        const next = [...slides];
        next[activeCardIndex].image = imageData;
        setSlides(next);
      }
    } catch (err) {
      console.error("AI Image Gen error:", err);
      alert("Erro ao gerar imagem.");
    } finally {
      setIsGeneratingImage(false);
    }
  };

  const scrollToIndex = (index: number) => {
    if (scrollRef.current) {
      const cardWidth = scrollRef.current.querySelector('.card-container-fixed')?.clientWidth || 0;
      const gap = 80;
      scrollRef.current.scrollTo({
        left: index * (cardWidth + gap),
        behavior: 'smooth'
      });
      setActiveCardIndex(index);
    }
  };

  const handleScroll = () => {
    if (scrollRef.current) {
      const cardWidth = scrollRef.current.querySelector('.card-container-fixed')?.clientWidth || 1;
      const gap = 80;
      const index = Math.round(scrollRef.current.scrollLeft / (cardWidth + gap));
      setActiveCardIndex(index);
    }
  };

  const exportAll = async () => {
    setIsExporting(true);
    try {
      const firstSlideText = slides[0]?.content || 'carousel';
      const cleanName = firstSlideText
        .replace(/<[^>]*>/g, '')
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
        .replace(/[^a-z0-9]/gi, '_')
        .toLowerCase()
        .substring(0, 35)
        .replace(/^_+|_+$/g, '');

      const timestamp = new Date().toISOString().split('T')[0];
      const filePrefix = cleanName ? `${cleanName}_${timestamp}` : `carousel_${timestamp}`;

      // Loop invertido: do último slide para o primeiro
      for (let i = slides.length; i >= 0; i--) {
        const node = cardRefs.current[i];
        if (node) {
          const dataUrl = await toPng(node, {
            canvasWidth: 1080,
            canvasHeight: 1350,
            pixelRatio: 1.5,
            style: { transform: 'scale(1)', margin: '0' }
          });
          const link = document.createElement('a');
          link.download = `${filePrefix}_slide_${i + 1}.png`;
          link.href = dataUrl;
          link.click();
          // Delay essencial para permitir múltiplos downloads no browser
          await new Promise(r => setTimeout(r, 800));
        }
      }
    } catch (err) {
      alert('Erro ao exportar. Tente novamente.');
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className={`flex flex-col md:flex-row h-screen w-screen overflow-hidden transition-colors duration-500 ${config.theme === 'dark' ? 'bg-[#0f171e] text-white' : 'bg-[#f1f5f9] text-slate-900'}`}>
      {/* Sidebar */}
      <aside className="w-full md:w-[420px] h-full flex flex-col border-r border-slate-200 dark:border-slate-800 bg-white dark:bg-[#0b141a] z-30 shadow-2xl shrink-0 overflow-y-auto no-scrollbar p-8">
        <div className="flex items-center gap-4 mb-10">
          <div className="bg-[#1d9bf0] p-2.5 rounded-2xl shadow-lg shadow-[#1d9bf0]/20">
             <svg className="w-6 h-6 text-white" fill="currentColor" viewBox="0 0 24 24"><path d="M23.643 4.937c-.835.37-1.732.62-2.675.733.962-.576 1.7-1.49 2.048-2.578-.9.534-1.897.922-2.958 1.13-.85-.904-2.06-1.47-3.4-1.47-2.572 0-4.658 2.086-4.658 4.66 0 .364.042.718.12 1.06-3.873-.195-7.304-2.05-9.602-4.868-.4.69-.63 1.49-.63 2.342 0 1.616.823 3.043 2.072 3.878-.764-.025-1.482-.234-2.11-.583v.06c0 2.257 1.605 4.14 3.737 4.568-.392.106-.803.162-1.227.162-.3 0-.593-.028-.877-.082.593 1.85 2.313 3.198 4.352 3.234-1.595 1.25-3.604 1.995-5.786 1.995-.376 0-.747-.022-1.112-.065 2.062 1.323 4.51 2.093 7.14 2.093 8.57 0 13.255-7.098 13.255-13.254 0-.2-.005-.402-.014-.602.91-.658 1.7-1.477 2.323-2.41z"></path></svg>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none uppercase text-slate-900 dark:text-white">Carousel Studio</h1>
            <p className="text-[10px] font-bold text-[#1d9bf0] tracking-widest mt-1">Twitter Edition</p>
          </div>
        </div>

        <EditorControls
          profile={profile} setProfile={setProfile}
          config={config} setConfig={setConfig}
          slides={slides} setSlides={setSlides}
          prompts={prompts} setPrompts={setPrompts}
          onBulkGenerate={handleBulkGenerate}
          onGenerateImage={handleAIImageGeneration}
          activeCardIndex={activeCardIndex}
          isGeneratingImage={isGeneratingImage}
          caption={caption}
          setCaption={setCaption}
        />

        <div className="mt-auto pt-8">
          <button
            onClick={exportAll}
            disabled={isExporting}
            className={`w-full py-5 rounded-2xl font-black text-sm uppercase tracking-widest flex items-center justify-center gap-3 shadow-xl transition-all ${isExporting ? 'bg-slate-100 text-slate-400' : 'bg-[#1d9bf0] text-white hover:bg-[#1a8cd8] active:scale-[0.98]'}`}
          >
            {isExporting ? (
              <><div className="w-5 h-5 border-2 border-slate-300 border-t-slate-500 rounded-full animate-spin" /> EXPORTANDO</>
            ) : 'BAIXAR PNG'}
          </button>
        </div>
      </aside>

      {/* Workspace */}
      <main className="flex-1 relative flex flex-col workspace-grid overflow-hidden">
        {/* Navigation Arrows */}
        <button 
          onClick={() => scrollToIndex(activeCardIndex - 1)}
          className="absolute left-8 top-1/2 -translate-y-1/2 z-20 p-5 bg-white/80 dark:bg-slate-800/80 rounded-full shadow-2xl backdrop-blur-xl border border-white/20 hover:scale-110 active:scale-90 transition disabled:opacity-0"
          disabled={activeCardIndex === 0}
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M15 19l-7-7 7-7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
        </button>

        <button 
          onClick={() => scrollToIndex(activeCardIndex + 1)}
          className="absolute right-8 top-1/2 -translate-y-1/2 z-20 p-5 bg-white/80 dark:bg-slate-800/80 rounded-full shadow-2xl backdrop-blur-xl border border-white/20 hover:scale-110 active:scale-90 transition disabled:opacity-0"
          disabled={activeCardIndex === slides.length}
        >
          <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path d="M9 5l7 7-7 7" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"></path></svg>
        </button>

        <div 
          ref={scrollRef}
          onScroll={handleScroll}
          className="carousel-viewport w-full h-full flex items-center gap-20 overflow-x-auto no-scrollbar px-[calc(50vw-216px)] md:px-[calc(50vw-270px-210px)]"
        >
          {slides.map((slide, index) => (
            <div key={slide.id} className={`card-container-fixed ${activeCardIndex === index ? 'active-card' : ''}`}>
               <div ref={el => cardRefs.current[index] = el} className="card-preview-wrapper rounded-[40px] overflow-hidden">
                  <CarouselCard
                    slide={slide}
                    profile={profile}
                    config={config}
                    onContentChange={(val) => {
                      const next = [...slides];
                      next[index].content = val;
                      setSlides(next);
                    }}
                  />
               </div>
            </div>
          ))}

          {/* Connected CTA Card */}
          <div className={`card-container-fixed ${activeCardIndex === slides.length ? 'active-card' : ''}`}>
             <div ref={el => cardRefs.current[slides.length] = el} className="card-preview-wrapper rounded-[40px] overflow-hidden">
                <CarouselCard
                  slide={{ id: 'cta', content: ctaContent }}
                  profile={profile}
                  config={config}
                  onContentChange={(val) => setCtaContent(val)}
                />
             </div>
          </div>
        </div>

        {/* Bottom Pagination */}
        <div className="absolute bottom-12 left-1/2 -translate-x-1/2 flex flex-col items-center gap-6">
           <div className="flex gap-2">
             {[...Array(slides.length + 1)].map((_, i) => (
               <div 
                 key={i} 
                 onClick={() => scrollToIndex(i)}
                 className={`h-2.5 rounded-full transition-all cursor-pointer ${activeCardIndex === i ? 'w-10 bg-[#1d9bf0]' : 'w-2.5 bg-slate-300 dark:bg-slate-700 hover:bg-slate-400'}`} 
               />
             ))}
           </div>
           <div className="bg-white/90 dark:bg-black/30 backdrop-blur-xl border border-white/20 px-8 py-2 rounded-full shadow-2xl">
              <span className="text-[10px] font-black uppercase tracking-[0.3em] opacity-60 text-slate-900 dark:text-white">Card {activeCardIndex + 1} de {slides.length + 1}</span>
           </div>
        </div>
      </main>

      {/* Loading Overlay */}
      {(isGenerating || isGeneratingImage) && (
        <div className="fixed inset-0 bg-white/60 dark:bg-slate-900/60 backdrop-blur-md z-[100] flex flex-col items-center justify-center">
           <div className="w-20 h-20 border-4 border-[#1d9bf0]/20 border-t-[#1d9bf0] rounded-full animate-spin mb-6" />
           <p className="font-black text-sm uppercase tracking-widest animate-pulse text-slate-900 dark:text-white">
             {isGeneratingImage ? "Pincelando sua imagem..." : "Destilando conhecimento..."}
           </p>
        </div>
      )}
    </div>
  );
};

export default App;
